// --- types.d.ts ---
export interface ForecastData {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F' | string;
  forecast: ForecastData[];
}

export interface WeatherHeaderProps {
  city: string;
  temperature: string;
  condition: string;
  unit: string;
}

export interface WeatherStatsProps {
  humidity: number;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastData[];
  unit: string;
}

export interface ForecastItemProps {
  data: ForecastData;
  unit: string;
}

export interface HookReturn {
  formattedTemp: string;
  formattedWind: string;
  displayUnit: string;
  processedForecast: ForecastData[];
  weatherIcon: string;
  ariaLabel: string;
}


// --- constants.ts ---
import { Props } from './types';

export const UNIT_LABELS = {
  C: '°C',
  F: '°F',
} as const;

export const WIND_SPEED_LABELS = {
  C: 'km/h',
  F: 'mph',
} as const;

export const WEATHER_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  'Partly Cloudy': '⛅',
  Default: '✨',
} as const;

export const DEFAULT_WEATHER_DATA: Props = {
  city: 'Unknown Location',
  temperature: 0,
  condition: 'Unknown',
  humidity: 0,
  windSpeed: 0,
  unit: 'C',
  forecast: [],
};

export const DAYS_SHORT: Record<string, string> = {
  Monday: 'Mon',
  Tuesday: 'Tue',
  Wednesday: 'Wed',
  Thursday: 'Thu',
  Friday: 'Fri',
  Saturday: 'Sat',
  Sunday: 'Sun',
} as const;

export const ARIA_LABELS = {
  WEATHER_CARD: (city: string) => `Current weather for ${city}`,
  HUMIDITY: 'Humidity level',
  WIND_SPEED: 'Wind speed',
  TEMPERATURE: (temp: string) => `Temperature is ${temp}`,
  FORECAST: 'Weather forecast for the upcoming days',
} as const;


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import type { Props, HookReturn } from './types';

export function useComponent(props: Props): HookReturn {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  const displayUnit = (unit && unit.length > 0) ? unit : 'C';

  const formattedTemp = `${temperature}°`;

  const windSuffix = displayUnit === 'F' ? 'mph' : 'km/h';
  const formattedWind = `${windSpeed} ${windSuffix}`;

  const getConditionIcon = (cond: string) => {
    const normalized = cond.toLowerCase();
    switch (normalized) {
      case 'sunny':
        return '☀️';
      case 'cloudy':
        return '☁️';
      case 'rainy':
        return '🌧️';
      case 'snowy':
        return '❄️';
      case 'thunderstorm':
        return '⛈️';
      default:
        return '☁️';
    }
  };

  const weatherIcon = getConditionIcon(condition);

  const processedForecast = forecast || [];

  const unitFullName = displayUnit === 'F' ? 'Fahrenheit' : 'Celsius';
  const ariaLabel = `Current weather in ${city}: ${temperature} degrees ${unitFullName}, ${condition}`;

  return {
    formattedTemp,
    formattedWind,
    displayUnit,
    processedForecast,
    weatherIcon,
    ariaLabel,
  };
}


// --- components/WeatherHeader.tsx ---
// components/WeatherHeader.tsx — reusable sub-component
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import type { WeatherHeaderProps } from '../types';

/**
 * Maps weather condition strings to emojis for visual representation.
 */
const getConditionEmoji = (condition: string): string => {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('partly')) return '⛅';
  if (c.includes('cloud') || c.includes('overcast')) return '☁️';
  if (c.includes('rain') || c.includes('drizzle') || c.includes('shower')) return '🌧️';
  if (c.includes('snow') || c.includes('ice') || c.includes('flurr')) return '❄️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  return '🌡️';
};

export function WeatherHeader({ city, temperature, condition, unit }: WeatherHeaderProps) {
  const emoji = getConditionEmoji(condition);

  return (
    <Stack
      direction="vertical"
      gap="var(--ggui-spacing-4, 16px)"
      aria-label={`Current weather in ${city}: ${temperature}${unit}, ${condition}`}
    >
      {/* City heading */}
      <Heading 
        level={2} 
        // @ts-ignore - Instructions specified size="xl" for Heading
        size="xl"
      >
        {city}
      </Heading>

      {/* Temperature and condition icon */}
      <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-12, 48px)">
        <Text
          style={{
            fontSize: 'var(--ggui-font-size-6xl, 60px)',
            fontWeight: 'var(--ggui-font-weight-bold, 700)',
          }}
        >
          {temperature}{unit}
        </Text>
        <Text
          style={{
            fontSize: 'var(--ggui-font-size-5xl, 48px)',
          }}
          aria-hidden="true"
        >
          {emoji}
        </Text>
      </Stack>

      {/* Weather condition text */}
      <Text
        color="var(--ggui-color-text-secondary, #6b7280)"
        size="lg"
      >
        {condition}
      </Text>
    </Stack>
  );
}


// --- components/WeatherStats.tsx ---
import React from 'react';
import { Stack, Text, Box } from '@ggui-ai/design/primitives';
import type { WeatherStatsProps } from '../types';

/**
 * WeatherStats component displays secondary weather metrics like humidity and wind speed.
 * It uses a horizontal layout with equal spacing between metrics.
 */
export function WeatherStats({ humidity, windSpeed }: WeatherStatsProps) {
  return (
    <Box
      paddingY="var(--ggui-spacing-4, 16px)"
      aria-label="Weather statistics"
    >
      <Stack direction="horizontal" justify="around" align="center">
        {/* Humidity Section */}
        <Stack align="center" gap={4}>
          <Text
            size="sm"
            color="var(--ggui-color-neutral-500, #6b7280)"
          >
            Humidity
          </Text>
          <Text
            weight="semibold"
            color="var(--ggui-color-neutral-900, #111827)"
            aria-label={`Humidity: ${humidity} percent`}
          >
            {humidity}%
          </Text>
        </Stack>

        {/* Wind Speed Section */}
        <Stack align="center" gap={4}>
          <Text
            size="sm"
            color="var(--ggui-color-neutral-500, #6b7280)"
          >
            Wind
          </Text>
          <Text
            weight="semibold"
            color="var(--ggui-color-neutral-900, #111827)"
            aria-label={`Wind: ${windSpeed}`}
          >
            {windSpeed}
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
}


