// --- components/ForecastItem.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastItemProps } from './types';

/**
 * ForecastItem displays a single day's weather summary in the forecast strip.
 */
export function ForecastItem({ data }: ForecastItemProps) {
  return (
    <Stack
      direction="vertical"
      align="center"
      gap={4}
      style={{ minWidth: '60px' }}
      aria-label={`${data.day}: High ${data.high}, Low ${data.low}`}
    >
      <Text size="sm" weight="semibold">
        {data.day}
      </Text>

      <Text size="xl">
        {data.icon}
      </Text>

      <Stack direction="horizontal" gap={4}>
        <Text size="sm" weight="medium">
          {data.high}°
        </Text>
        <Text size="sm" color="var(--ggui-color-neutral-500)">
          {data.low}°
        </Text>
      </Stack>
    </Stack>
  );
}


// --- ui.tsx ---
import React from 'react';
import type { Props } from './types';
import { useWeatherLogic } from './hooks';
import { Container, Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { WeatherHeader, WeatherStats, ForecastStrip } from './components';

/**
 * WeatherCard Component
 * 
 * Orchestrates the weather display by processing data via the useWeatherLogic hook
 * and rendering sub-components (Header, Stats, Forecast) within a Card.
 */
const WeatherCard: React.FC<Props> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}) => {
  // Logic Integration
  const {
    formattedTemp,
    formattedWind,
    displayUnit,
    processedForecast,
    ariaLabel,
  } = useWeatherLogic(temperature, unit, windSpeed, forecast, condition);

  return (
    <Container maxWidth="sm" padding={24}>
      <Card
        shadow="md"
        padding={24}
        aria-label={ariaLabel}
        border
        radius="lg"
      >
        <Stack gap={24} direction="vertical" align="stretch">
          {/* Top Section: Basic Weather Info */}
          <WeatherHeader
            city={city}
            temperature={formattedTemp}
            condition={condition}
            unit={displayUnit}
          />

          {/* Middle Section: Detailed Stats */}
          <WeatherStats 
            humidity={humidity} 
            windSpeed={formattedWind} 
          />

          {/* Divider for visual separation */}
          <Divider 
            margin={0} 
            color="var(--ggui-color-neutral-200, #e5e7eb)" 
          />

          {/* Bottom Section: 5-Day Forecast */}
          <ForecastStrip 
            forecast={processedForecast} 
            unit={displayUnit} 
          />
        </Stack>
      </Card>
    </Container>
  );
};

export default WeatherCard;


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
